INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04610', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體如同社會的縮影，成員可以在團體中練習新行為，然後運用在真實生活中。下列何者與前述 內容無關？', '["團體提供所需要的歸屬感，成員在此情況下彼此認同，然後感覺自己是團體中的一部分", "人際交往的困難，可能呈現在該成員和團體中其他成員的互動關係中", "在團體情境中，某成員人際交往的慣常模式會被複製", "團體工作過程可能可以仿效某成員的家庭經驗，讓團體成員討論家庭動力的議題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04611', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關「社會打混」（socialloafing）敘述何者錯誤？', '["在社團、辦公室、社區、教室裡，打混的人實屬常見", "與他人一起工作時，團體任務在增加，但個人努力卻減少", "利用多人一起工作機會，有人會搭便車，分享團體創造出來的成果", "「冤大頭效益」（suckereffect）會導致後續的「搭便車效益」（freerideeffect）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04612', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不屬於IrvinD.Yalom所羅列的團體療效因子？', '["早期家庭經驗得到矯正性經驗的重視", "利他性", "普遍性", "與團體領導者支持穩定的信賴關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04613', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '佳文與葛拉瑟（GarvinandGlasser）所提出的治療模型（remedialmodel）主要概念是「治療目標」， 治療目標的選定原則，下列何者錯誤？', '["特定的治療目標必須要被建立，作為團體中每一個成員的目標", "工作者依照治療目標來協助團體發展規範系統與價值", "工作者依照每一個成員個別不同的治療目標來界定團體目標", "工作者對團體會期內容的先設是立基於對個人治療目標的表達，以及發生於團體內的結構特性等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04614', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關場域論敘述，何者正確？', '["社會心理學的場域論（fieldtheory）是由黎文（KurtLewin）所初創，其提出「人類行為是團體 與其環境的函數」", "場域論認為個人的內在可以決定其行為表現的結果，基本上，每一個行動均被行動發生的場域 所影響", "場域論的主要概念，包括：生活空間、此時此地、支持體系", "場域論幫助團體工作者理解團體成員的特質與團體社會情境的互動決定了成員的行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04615', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者最符合結構性團體的設計精神？', '["當成員因上下班延遲出席半小時，導致領導者延遲半小時開始，也應該延後半小時結束，以彌 補短缺的時間，讓所有團體內容能被執行", "團體結束前，成員之一突然大哭，說在昨晚約會時被性侵，其遭遇讓成員既震驚又不平，儘管 預定結束時間已到，領導者認為情況特殊不該貿然讓其離開，決定延長團體的時間安撫其情緒", "領導者在設計活動時會考量每位成員都能平均參與", "高結構的團體目標最有利於成員發展凝聚力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04616', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不該被列入處遇團體成員「非計畫結束」的原因？', '["領導者在篩選團體成員的過程不謹慎，以致某團體成員異質性落差大而離開團體", "團體形成次團體，以致某成員感覺在團體內受到排擠而離開", "某成員是團體中唯一的男性而離開", "成員完成預定行為改變目標而離開"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04617', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體思考的敘述，下列何者錯誤？①指團體加諸於個人的控制力，讓個體的意見不容易彰顯', '["三個臭皮匠勝過一個諸葛亮，團體思考相較於個人更不易發生風險決策的機會", "為了增進團 體的決策力，團體應該催化團體思考的發生", "高凝聚的團體容易讓成員陷入團體思考", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04618', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關焦點團體的實施特色，下列敘述何者正確？①焦點團體因為是針對特定主題的討論，成員間', '["是一種半結構式的團體模式", "通常成員的人數較多，人數約在 25 人以上， 以便充分蒐集資料讓討論內容有代表性", "會充分討論一個問題後，才到下一個問題  ⑤會採用 比較自由的方式，在所有題目間跳動發表意見，增加討論的流暢性", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04619', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「囊括所有成員意見」的內涵，下列何者錯誤？', '["社會工作者在組織團體時，應避免種族或性別上的歧視或偏見", "團體活動設計，應避免影響某類成員參與的機會", "運用繞圈發言的技術，誘使所有成員都參與", "團體領導者在統整成員意見時，務必讓每位成員的意見都被聽見且得到適度回應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "1e560fe92ef2", "answer_pdf_sha1": "c6ca9bd2541c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
